const input = $input.first().json;

const rawText = input.output || input.text || JSON.stringify(input);

const cleaned = rawText.replace(/```json|```/g, "").trim();

let cliData = {};
try {
  cliData = JSON.parse(cleaned);
} catch (e) {
  cliData = input;
}

return [{
  json: {
    scanId: cliData.scanId || input.scanId || "",
    host: cliData.host || input.host || "",
    type: "cli_commands",
    cli_commands: cliData.cli || [],
    cli_summary: cliData.summary || "",
    warnings: cliData.warnings || []
  }
}];

// ============================================================
// FortiWeb On-Demand Config Parser v3
// Clean extraction — no duplicates, no name-only noise
// ============================================================

function escapeRegex(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function getSet(body, key) {
  const re = new RegExp('\\bset ' + escapeRegex(key) + '\\s+(.+)');
  const m = body.match(re);
  return m ? m[1].trim().replace(/^"|"$/g, '') : null;
}

// Strict section extractor — only extracts the EXACT named config section
// and stops at the matching top-level "end" without bleeding into subsections
function extractSection(text, sectionPath) {
  const escaped = escapeRegex(sectionPath);
  const start = text.search(new RegExp('\\bconfig\\s+' + escaped + '\\s*\\n'));
  if (start === -1) return null;

  let depth = 0;
  let i = start;
  const lines = text.slice(start).split('\n');
  const sectionLines = [];

  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed.startsWith('config ')) depth++;
    if (trimmed === 'end') {
      depth--;
      if (depth === 0) {
        sectionLines.push(line);
        break;
      }
    }
    sectionLines.push(line);
  }

  return sectionLines.join('\n');
}

// Extract only TOP-LEVEL edit blocks from a section (not nested ones)
function extractTopLevelBlocks(sectionText) {
  if (!sectionText) return [];
  const blocks = [];
  const lines = sectionText.split('\n');
  let depth = 0;
  let currentName = null;
  let currentLines = [];
  let inTopEdit = false;

  for (const line of lines) {
    const trimmed = line.trim();

    if (trimmed.startsWith('config ')) depth++;

    if (depth === 1 && trimmed.startsWith('edit ')) {
      currentName = trimmed.replace(/^edit\s+/, '').replace(/^"|"$/g, '').trim();
      currentLines = [];
      inTopEdit = true;
    } else if (depth === 1 && trimmed === 'next' && inTopEdit) {
      blocks.push({ name: currentName, body: currentLines.join('\n') });
      currentName = null;
      currentLines = [];
      inTopEdit = false;
    } else if (inTopEdit) {
      currentLines.push(line);
    }

    if (trimmed === 'end') depth--;
  }

  return blocks;
}

function stripNulls(obj) {
  return JSON.parse(JSON.stringify(obj, (k, v) => v === null ? undefined : v));
}

// Only keep blocks that have at least one field beyond just a name
function hasData(obj) {
  const keys = Object.keys(obj).filter(k => k !== 'name' && k !== 'type');
  return keys.length > 0;
}

// ── Get raw config from Data Table ────────────────────────
const row = $input.first().json;
if (!row || !row.value) throw new Error("❌ Raw config not found in Data Table");
const rawConfig = typeof row.value === 'string' ? row.value : JSON.stringify(row.value);

// ── 1. Server Policies ─────────────────────────────────────
const policies = [];
const policySection = extractSection(rawConfig, 'server-policy policy');
if (policySection) {
  for (const b of extractTopLevelBlocks(policySection)) {
    const obj = {
      name: b.name,
      vserver: getSet(b.body, 'vserver'),
      server_pool: getSet(b.body, 'server-pool'),
      web_protection: getSet(b.body, 'web-protection-profile'),
      status: getSet(b.body, 'status'),
      protocol: getSet(b.body, 'protocol'),
      deployment_mode: getSet(b.body, 'deployment-mode'),
    };
    if (hasData(obj)) policies.push(stripNulls(obj));
  }
}

// ── 2. HTTP Header Security ────────────────────────────────
const httpHeaderSecurity = [];
const headerSection = extractSection(rawConfig, 'waf http-header-security');
if (headerSection) {
  for (const b of extractTopLevelBlocks(headerSection)) {
    const obj = {
      name: b.name,
      status: getSet(b.body, 'status'),
      x_frame_options: getSet(b.body, 'x-frame-options'),
      x_content_type: getSet(b.body, 'x-content-type-options'),
      hsts: getSet(b.body, 'strict-transport-security'),
      hsts_max_age: getSet(b.body, 'strict-transport-security-max-age'),
      csp: getSet(b.body, 'content-security-policy'),
      csp_value: getSet(b.body, 'content-security-policy-value'),
      referrer_policy: getSet(b.body, 'referrer-policy'),
    };
    if (hasData(obj)) httpHeaderSecurity.push(stripNulls(obj));
  }
}

// ── 3. Inline Web Protection Profiles ─────────────────────
const inlineProfiles = [];
const inlineSection = extractSection(rawConfig, 'waf web-protection-profile inline-protection');
if (inlineSection) {
  for (const b of extractTopLevelBlocks(inlineSection)) {
    const obj = {
      name: b.name,
      type: 'inline',
      signature_rule: getSet(b.body, 'signature-rule'),
      http_protocol_restrict: getSet(b.body, 'http-protocol-parameter-restriction'),
      http_header_security: getSet(b.body, 'http-header-security'),
      bot_mitigate_policy: getSet(b.body, 'bot-mitigate-policy'),
      ip_intelligence: getSet(b.body, 'ip-intelligence'),
      custom_access_policy: getSet(b.body, 'custom-access-policy'),
      webshell_detection: getSet(b.body, 'webshell-detection-policy'),
      file_upload_policy: getSet(b.body, 'file-upload-policy'),
      syntax_attack_detection: getSet(b.body, 'syntax-based-attack-detection'),
      client_management: getSet(b.body, 'client-management'),
    };
    if (hasData(obj)) inlineProfiles.push(stripNulls(obj));
  }
}

// ── 4. Offline Web Protection Profiles ────────────────────
const offlineProfiles = [];
const offlineSection = extractSection(rawConfig, 'waf web-protection-profile offline-protection');
if (offlineSection) {
  for (const b of extractTopLevelBlocks(offlineSection)) {
    const obj = {
      name: b.name,
      type: 'offline',
      signature_rule: getSet(b.body, 'signature-rule'),
      http_protocol_restrict: getSet(b.body, 'http-protocol-parameter-restriction'),
      http_header_security: getSet(b.body, 'http-header-security'),
      ip_intelligence: getSet(b.body, 'ip-intelligence'),
      webshell_detection: getSet(b.body, 'webshell-detection-policy'),
      client_management: getSet(b.body, 'client-management'),
    };
    if (hasData(obj)) offlineProfiles.push(stripNulls(obj));
  }
}

// ── 5. Signature Rules ─────────────────────────────────────
const signatureRules = [];
const sigSection = extractSection(rawConfig, 'waf signature');
if (sigSection) {
  for (const b of extractTopLevelBlocks(sigSection)) {
    const obj = {
      name: b.name,
      status: getSet(b.body, 'status'),
      alert_only: getSet(b.body, 'alert-only'),
      sql_injection: getSet(b.body, 'sql-injection'),
      xss: getSet(b.body, 'cross-site-scripting'),
      main_class_action: getSet(b.body, 'main-class-action'),
      sub_class_action: getSet(b.body, 'sub-class-action'),
    };
    if (hasData(obj)) signatureRules.push(stripNulls(obj));
  }
}

// ── 6. HTTP Protocol Constraints ───────────────────────────
const httpConstraints = [];
const constraintSection = extractSection(rawConfig, 'waf http-protocol-parameter-restriction');
if (constraintSection) {
  for (const b of extractTopLevelBlocks(constraintSection)) {
    const obj = {
      name: b.name,
      status: getSet(b.body, 'status'),
      illegal_header: getSet(b.body, 'illegal-header-name-or-value'),
      max_url_length: getSet(b.body, 'max-url-length'),
      max_header_length: getSet(b.body, 'max-http-header-length'),
      max_body_length: getSet(b.body, 'max-http-body-length'),
    };
    if (hasData(obj)) httpConstraints.push(stripNulls(obj));
  }
}

// ── 7. Custom Protection Rules ─────────────────────────────
const customRules = [];
const customSection = extractSection(rawConfig, 'waf custom-protection-rule');
if (customSection) {
  for (const b of extractTopLevelBlocks(customSection)) {
    const obj = {
      name: b.name,
      action: getSet(b.body, 'action'),
      severity: getSet(b.body, 'severity'),
      status: getSet(b.body, 'status'),
    };
    if (hasData(obj)) customRules.push(stripNulls(obj));
  }
}

// ── 8. Bot Mitigation Policies ─────────────────────────────
const botPolicies = [];
const botSection = extractSection(rawConfig, 'waf bot-mitigate-policy');
if (botSection) {
  for (const b of extractTopLevelBlocks(botSection)) {
    const obj = {
      name: b.name,
      status: getSet(b.body, 'status'),
      action: getSet(b.body, 'action'),
    };
    if (hasData(obj)) botPolicies.push(stripNulls(obj));
  }
}

// ── 9. IP Intelligence ─────────────────────────────────────
const ipIntelligence = [];
const ipSection = extractSection(rawConfig, 'waf ip-intelligence');
if (ipSection) {
  for (const b of extractTopLevelBlocks(ipSection)) {
    const obj = {
      name: b.name,
      status: getSet(b.body, 'status'),
      action: getSet(b.body, 'action'),
    };
    if (hasData(obj)) ipIntelligence.push(stripNulls(obj));
  }
}

// ── Build final result ─────────────────────────────────────
const result = {
  summary: {
    policies_count: policies.length,
    inline_profiles_count: inlineProfiles.length,
    offline_profiles_count: offlineProfiles.length,
    signature_rules_count: signatureRules.length,
    http_header_rules_count: httpHeaderSecurity.length,
    custom_rules_count: customRules.length,
    http_constraints_count: httpConstraints.length,
  },
  policies,
  web_protection_profiles: [...inlineProfiles, ...offlineProfiles],
  http_header_security: httpHeaderSecurity,
  signature_rules: signatureRules,
  http_protocol_constraints: httpConstraints,
  custom_protection_rules: customRules,
  bot_mitigation_policies: botPolicies,
  ip_intelligence_policies: ipIntelligence,
};

// ── Debug log ──────────────────────────────────────────────
console.log("✅ FortiWeb config parsed successfully");
console.log("Policies:", policies.length);
console.log("Inline Profiles:", inlineProfiles.length);
console.log("Offline Profiles:", offlineProfiles.length);
console.log("Signature Rules:", signatureRules.length);
console.log("HTTP Header Rules:", httpHeaderSecurity.length);
console.log("Custom Rules:", customRules.length);

return [{ json: result }];

const item = $input.first().json;
const zap = item.body || {};
const fortiweb = {
  policies: item.policies || [],
  web_protection_profiles: item.web_protection_profiles || [],
  http_header_security: item.http_header_security || [],
  signature_rules: item.signature_rules || [],
  http_protocol_constraints: item.http_protocol_constraints || [],
  custom_protection_rules: item.custom_protection_rules || []
};
return [{ json: { scanId: zap.scanId || null, host: zap.targetUrl || null, zap, fortiweb } }];

const text = $input.first().json.output;

// Try ---REPORT--- marker first, fall back to everything before ---JSON---
const reportMatch = text.match(/---REPORT---([\s\S]*?)---JSON---/) || 
                    text.match(/([\s\S]*?)---JSON---/);

const jsonMatch = text.match(/---JSON---([\s\S]*?)$/);

if (!jsonMatch) {
  return [{ json: { error: "No ---JSON--- marker found", raw: text.substring(0, 300) } }];
}

const report = reportMatch ? reportMatch[1].trim() : "";

const clean = jsonMatch[1]
  .replace(/```json|```/g, "")
  .replace(/---.*?---/g, "")
  .replace(/"[^"]*"|(\/\/[^\n]*)/g, (m, comment) => comment ? "" : m)
  .replace(/,(\s*[}\]])/g, "$1")
  .trim();

let parsed;
try {
  parsed = JSON.parse(clean);
} catch (e) {
  const pos = parseInt(e.message.match(/position (\d+)/)?.[1] || 0);
  return [{ json: { 
    error: e.message, 
    near: clean.substring(Math.max(0, pos - 50), pos + 50),
    raw: clean.substring(0, 500)
  }}];
}

return [{
  json: {
    report:     report,
    scanId:     parsed.scanId || null,
    host:       parsed.host || null,
    structured: parsed,
    raw_output: text
  }
}];

